# Category: use_after_free

#include <unordered_map>
#include <string>
#include <time.h>

struct Session {
  std::string user_id;
  time_t creation_time;
};

class SessionCache {
 private:
  std::unordered_map<std::string, Session> cache;

 public:
  std::string createSession(const std::string& user_id) {
    Session session{user_id, time(nullptr)};
    cache[session.user_id] = session;
    return session.user_id;
  }

  Session* getSession(const std::string& session_id) {
    auto it = cache.find(session_id);
    if (it != cache.end() && it->second.creation_time + 3600 > time(nullptr)) {
      return &it->second;
    }
    return nullptr;
  }

  void invalidateSession(const std::string& session_id) {
    cache.erase(session_id);
  }
};

int main() {
  SessionCache session_cache;

  // Create a new session
  std::string session_id = session_cache.createSession("user1");

  // Get the session data
  Session* session = session_cache.getSession(session_id);
  if (session) {
    std::cout << "User ID: " << session->user_id << std::endl;
  } else {
    std::cout << "Session not found" << std::endl;
  }

  // Invalidate the session
  session_cache.invalidateSession(session_id);

  return 0;
}